        "OtpService.java": "@Service
@RequiredArgsConstructor
public class OtpService {

    private final OtpRepository otpRepository;

    public OtpResponse requestOtp(String phone) {
        String otp = generateOtp();
        String requestId = UUID.randomUUID().toString();

        otpRepository.saveOtp(requestId, otp, 300); // 5 minutes TTL

        return new OtpResponse(requestId, 300);
    }

    public VerifyResponse verifyOtp(String requestId, String otp) {
        String storedOtp = otpRepository.getOtp(requestId);

        if (storedOtp == null) {
            return new VerifyResponse(false);
        }

        long attempts = otpRepository.incrementAttempts(requestId);

        if (attempts > 3) {
            throw new RuntimeException("Max attempts exceeded");
        }

        boolean verified = storedOtp.equals(otp);
        return new VerifyResponse(verified);
    }

    private String generateOtp() {
        return String.format("%06d", new Random().nextInt(1000000));
    }
}",
