        "main.py": "from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
import uuid
import random
import time
from typing import Dict

app = FastAPI()

# In-memory storage (use Redis in production)
otp_storage: Dict[str, dict] = {}

class OtpRequest(BaseModel):
    phone: str

class OtpResponse(BaseModel):
    requestId: str
    expiresIn: int

class VerifyRequest(BaseModel):
    requestId: str
    otp: str

class VerifyResponse(BaseModel):
    verified: bool

@app.post('/otp/request', response_model=OtpResponse)
async def request_otp(request: OtpRequest):
    if not request.phone:
        raise HTTPException(status_code=400, detail='phone required')

    otp = f'{random.randint(100000, 999999):06d}'
    request_id = str(uuid.uuid4())

    otp_storage[request_id] = {
        'otp': otp,
        'phone': request.phone,
        'created_at': time.time(),
        'attempts': 0
    }

    return OtpResponse(requestId=request_id, expiresIn=300)

@app.post('/otp/verify', response_model=VerifyResponse)
async def verify_otp(request: VerifyRequest):
    if request.requestId not in otp_storage:
        return VerifyResponse(verified=False)

    otp_data = otp_storage[request.requestId]

    # Check if OTP expired (5 minutes)
    if time.time() - otp_data['created_at'] > 300:
        del otp_storage[request.requestId]
        return VerifyResponse(verified=False)

    # Check attempts
    otp_data['attempts'] += 1
    if otp_data['attempts'] > 3:
        raise HTTPException(status_code=429, detail='Max attempts exceeded')

    # Verify OTP
    verified = otp_data['otp'] == request.otp

    if verified:
        del otp_storage[request.requestId]

    return VerifyResponse(verified=verified)

if __name__ == '__main__':
    import uvicorn
    uvicorn.run(app, host='0.0.0.0', port=8000)"
    }
}

