        "server.js": "const express = require('express');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// In-memory storage (use Redis in production)
const otpStorage = new Map();

// Generate 6-digit OTP
function generateOtp() {
    return Math.floor(100000 + Math.random() * 900000).toString();
}

// POST /otp/request
app.post('/otp/request', (req, res) => {
    const { phone } = req.body;

    if (!phone) {
        return res.status(400).json({ error: 'phone required' });
    }

    const otp = generateOtp();
    const requestId = uuidv4();

    // Store OTP with 5-minute TTL
    otpStorage.set(requestId, {
        otp,
        phone,
        createdAt: Date.now(),
        attempts: 0
    });

    // Auto-cleanup after 5 minutes
    setTimeout(() => {
        otpStorage.delete(requestId);
    }, 5 * 60 * 1000);

    res.json({
        requestId,
        expiresIn: 300
    });
});

// POST /otp/verify
app.post('/otp/verify', (req, res) => {
    const { requestId, otp } = req.body;

    if (!requestId || !otp) {
        return res.status(400).json({ error: 'requestId and otp required' });
    }

    const otpData = otpStorage.get(requestId);

    if (!otpData) {
        return res.json({ verified: false });
    }

    // Check if expired
    if (Date.now() - otpData.createdAt > 5 * 60 * 1000) {
        otpStorage.delete(requestId);
        return res.json({ verified: false });
    }

    // Increment attempts
    otpData.attempts++;

    if (otpData.attempts > 3) {
        otpStorage.delete(requestId);
        return res.status(429).json({ error: 'Max attempts exceeded' });
    }

    // Verify OTP
    const verified = otpData.otp === otp;

    if (verified) {
        otpStorage.delete(requestId);
    }

    res.json({ verified });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`OTP Service running on port ${PORT}`);
});",
